// Fetch all subjects from Airtable
// Uses env vars from docker-compose: AIRTABLE_API_KEY, AIRTABLE_BASE_ID
const key = process.env.AIRTABLE_API_KEY;
const base = process.env.AIRTABLE_BASE_ID || 'app8IWoPTQHOyXZQQ';

if (!key) throw new Error('AIRTABLE_API_KEY no configurada en variables de entorno');

const fields = ['nombre', 'genero', 'total_runs', 'ultimo_uso'];
const fieldParams = fields.map(f => 'fields%5B%5D=' + f).join('&');
const url = 'https://api.airtable.com/v0/' + base + '/Subjects?' + fieldParams + '&sort%5B0%5D%5Bfield%5D=ultimo_uso&sort%5B0%5D%5Bdirection%5D=desc';

const res = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  headers: { 'Authorization': 'Bearer ' + key }
});

const subjects = (res.records || []).map(r => ({
  id: r.id,
  nombre: r.fields.nombre || '',
  genero: r.fields.genero || '',
  total_runs: r.fields.total_runs || 0,
  ultimo_uso: r.fields.ultimo_uso || null
}));

console.log('[Subjects API] Devolviendo', subjects.length, 'personajes');
return [{ json: { subjects } }];
